module parallel2serial
(
    input clk,
    input rst_n,
    input [3:0] d,
    output valid_out,
    output dout
);
reg [2:0] cnt;
reg [3:0] data;
reg valid;
assign dout = data[3];
assign valid_out = valid;
always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
        cnt <= 3'd0;
    else if (cnt == 3'd3)
        cnt <= 3'd0;
    else
        cnt <= cnt + 1;
end
always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
        valid <= 1'b0;
    else if (cnt == 3'd3)
        valid <= 1'b1;
    else
        valid <= 1'b0;
end
always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
        data <= 4'd0;
    else if (cnt == 3'd3) begin
        data <= d;
    end
    else begin
        data <= {data[2:0], data[3]};
    end
end
endmodule
